import os
import json
import pymysql
from flask import Request

DB_HOST = os.getenv("DB_HOST")
DB_USER = os.getenv("DB_USER")
DB_PASSWORD = os.getenv("DB_PASSWORD")
DB_NAME = os.getenv("DB_NAME")
DB_PORT = int(os.getenv("DB_PORT", "3306"))

ALLOWED_TABLES = {"products"}
ALLOWED_COLUMNS = {
    "products": {
        "id": "id",
        "name": "name",
        "category": "category",
        "status": "status",
        "price": "price",
        "created_at": "created_at",
    }
}
ALLOWED_OPERATORS = {
    "eq": "=",
    "ne": "!=",
    "lt": "<",
    "lte": "<=",
    "gt": ">",
    "gte": ">=",
    "like": "LIKE",
    "in": "IN",
}
ALLOWED_SORT_DIRECTIONS = {"asc", "desc"}


def get_connection():
    return pymysql.connect(
        host=DB_HOST,
        user=DB_USER,
        password=DB_PASSWORD,
        database=DB_NAME,
        port=DB_PORT,
        cursorclass=pymysql.cursors.DictCursor,
        autocommit=True,
    )


def json_response(payload, status=200):
    return (json.dumps(payload, default=str), status, {"Content-Type": "application/json"})


def parse_value(raw, op):
    if op == "in":
        if isinstance(raw, list):
            return raw
        return [v.strip() for v in str(raw).split(",") if v.strip()]
    return raw


def search(request: Request):
    try:
        table = request.args.get("table", "products")
        if table not in ALLOWED_TABLES:
            return json_response({"error": "Invalid table"}, 400)

        filters_param = request.args.get("filters")
        if filters_param:
            try:
                filters = json.loads(filters_param)
            except Exception:
                return json_response({"error": "Invalid filters JSON"}, 400)
        else:
            filters = []

        select_param = request.args.get("select")
        if select_param:
            requested_columns = [c.strip() for c in select_param.split(",") if c.strip()]
        else:
            requested_columns = list(ALLOWED_COLUMNS[table].keys())

        resolved_columns = []
        for col in requested_columns:
            if col not in ALLOWED_COLUMNS[table]:
                return json_response({"error": f"Invalid column: {col}"}, 400)
            resolved_columns.append(ALLOWED_COLUMNS[table][col])

        sort_by = request.args.get("sort_by", "id")
        sort_dir = request.args.get("sort_dir", "asc").lower()
        if sort_by not in ALLOWED_COLUMNS[table]:
            return json_response({"error": "Invalid sort_by"}, 400)
        if sort_dir not in ALLOWED_SORT_DIRECTIONS:
            return json_response({"error": "Invalid sort_dir"}, 400)

        try:
            limit = int(request.args.get("limit", "100"))
            offset = int(request.args.get("offset", "0"))
        except ValueError:
            return json_response({"error": "limit and offset must be integers"}, 400)

        if limit < 1 or limit > 1000 or offset < 0:
            return json_response({"error": "Invalid pagination values"}, 400)

        where_clauses = []
        params = []

        for item in filters:
            if not isinstance(item, dict):
                return json_response({"error": "Each filter must be an object"}, 400)

            field = item.get("field")
            op = item.get("op", "eq")
            value = item.get("value")

            if field not in ALLOWED_COLUMNS[table]:
                return json_response({"error": f"Invalid filter field: {field}"}, 400)
            if op not in ALLOWED_OPERATORS:
                return json_response({"error": f"Invalid operator: {op}"}, 400)

            column = ALLOWED_COLUMNS[table][field]
            sql_op = ALLOWED_OPERATORS[op]
            parsed_value = parse_value(value, op)

            if op == "in":
                if not parsed_value:
                    return json_response({"error": f"IN filter for {field} requires at least one value"}, 400)
                placeholders = ", ".join(["%s"] * len(parsed_value))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(parsed_value)
            else:
                where_clauses.append(f"`{column}` {sql_op} %s")
                params.append(parsed_value)

        sql = f"SELECT {', '.join(f'`{c}`' for c in resolved_columns)} FROM `{table}`"
        if where_clauses:
            sql += " WHERE " + " AND ".join(where_clauses)
        sql += f" ORDER BY `{ALLOWED_COLUMNS[table][sort_by]}` {sort_dir.upper()} LIMIT %s OFFSET %s"
        params.extend([limit, offset])

        with get_connection() as conn:
            with conn.cursor() as cursor:
                cursor.execute(sql, params)
                rows = cursor.fetchall()

        return json_response(
            {
                "table": table,
                "count": len(rows),
                "limit": limit,
                "offset": offset,
                "results": rows,
            },
            200,
        )
    except Exception as e:
        return json_response({"error": "Internal server error", "details": str(e)}, 500)